export const CONTENT_HTML = "\r\n<p class=\"intro\">Bạn đã bao giờ thấy một bức vẽ chì mà cục đá trông <em>chắc nịch</em>, cục bông trông <em>mềm mại</em>, cái kính trông <em>trong suốt</em>? Cùng là chì đen trắng — nhưng vật liệu khác nhau. Đó là ma thuật của <strong>lý thuyết vật liệu</strong>.</p>\r\n\r\n<div class=\"stats break-half\">\r\n  <div class=\"stat\"><div class=\"stat-num\">4</div><div class=\"stat-label\">Thuộc tính chính</div><div class=\"stat-sub\">Của mọi vật liệu</div></div>\r\n  <div class=\"stat\"><div class=\"stat-num\">5</div><div class=\"stat-label\">Nhóm vật liệu</div><div class=\"stat-sub\">Cần master</div></div>\r\n  <div class=\"stat\"><div class=\"stat-num\">100%</div><div class=\"stat-label\">Có thể vẽ</div><div class=\"stat-sub\">Bằng đúng nguyên tắc</div></div>\r\n</div>\r\n\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>01</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Định nghĩa</p>\r\n    <h2 class=\"div-title\">Lý thuyết vật liệu là gì?</h2>\r\n  </div>\r\n</div>\r\n\r\n<p><strong>Lý thuyết vật liệu</strong> <em>(Material Theory / Surface Study)</em> nghiên cứu cách ánh sáng tương tác với các bề mặt khác nhau — kim loại, vải, gỗ, kính, da, nước... Mỗi vật liệu có \"chữ ký thị giác\" riêng, được xác định bởi cách nó <strong>phản xạ, hấp thụ, tán xạ hoặc truyền ánh sáng</strong>.</p>\r\n\r\n<p>Đây là lý thuyết nằm giữa shading (tả khối) và texture (chất liệu). Hiểu lý thuyết vật liệu, bạn chọn được kỹ thuật phù hợp để vẽ bất kỳ bề mặt nào — từ kim cương đến nhung.</p>\r\n\r\n<div class=\"gls\">\r\n  <p class=\"gls-head\">A — 4 thuộc tính vật liệu</p>\r\n  <div class=\"gls-body\">\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Reflectivity<small>Độ phản xạ</small></p><p class=\"gls-def\">Lượng ánh sáng bị phản xạ. Gương 100%, vải nhung ~5%.</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Roughness<small>Độ nhám</small></p><p class=\"gls-def\">Bề mặt phẳng hay gồ ghề. Quyết định highlight \"cứng\" hay \"mềm\".</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Transparency<small>Độ trong</small></p><p class=\"gls-def\">Ánh sáng xuyên qua được không. Kính trong, sữa mờ, gỗ đục.</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Subsurface<small>Tán xạ dưới bề mặt</small></p><p class=\"gls-def\">Ánh sáng xuyên nhẹ vào vật rồi ra lại. Da, sáp, đá cẩm thạch.</p></div>\r\n  </div>\r\n</div>\r\n\r\n<!-- IMG_01: \"Different material sphere reference metal fabric glass wood\" -->\r\n<div class=\"bleed break\" data-img=\"IMG_01\">\r\n  <span class=\"bleed-kw-label\">🔍 IMG_01</span>\r\n  <p class=\"bleed-kw\">Different material sphere reference metal fabric glass wood</p>\r\n  <p class=\"bleed-note\">Cùng 1 hình dạng quả cầu — 5 vật liệu khác nhau cho 5 cảm giác khác</p>\r\n  <span class=\"bleed-cap\">Fig. 01 · Material spheres</span>\r\n</div>\r\n\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>02</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Phân loại</p>\r\n    <h2 class=\"div-title\">5 nhóm vật liệu</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Trong thực hành, vật liệu được chia thành 5 nhóm theo đặc tính ánh sáng. Học được 5 nhóm này là đủ để vẽ 95% vật trong đời:</p>\r\n\r\n<div class=\"pr-table\">\r\n  <div class=\"pr-row\"><span class=\"pr-i\">i.</span><div class=\"pr-n\">Kim loại<small>Metallic</small></div><div class=\"pr-d\">Phản xạ cao, highlight cứng và sắc. Core shadow rất đậm. Phản xạ môi trường xung quanh (tròn, méo tùy bề mặt).</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">ii.</span><div class=\"pr-n\">Bóng nhẵn<small>Glossy / Plastic</small></div><div class=\"pr-d\">Phản xạ vừa, highlight rõ nhưng mềm hơn kim loại. Nhựa, gốm men, sơn xe hơi.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">iii.</span><div class=\"pr-n\">Mờ đục<small>Matte</small></div><div class=\"pr-d\">Ít phản xạ, highlight mờ và rộng. Chuyển tiếp êm. Vải, giấy, đá không đánh bóng.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">iv.</span><div class=\"pr-n\">Trong &amp; bán trong<small>Transparent</small></div><div class=\"pr-d\">Kính, nước, thuỷ tinh. Có highlight sắc, có khúc xạ, có refraction phía sau.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">v.</span><div class=\"pr-n\">Tán xạ<small>Subsurface Scattering</small></div><div class=\"pr-d\">Ánh sáng xuyên nhẹ vào rồi ra. Da người, sáp, trái cây. Làm rìa vật \"phát sáng\" nhẹ.</div></div>\r\n</div>\r\n\r\n<!-- IMG_02: \"Metal chrome ball reflection environment reference\" -->\r\n<div class=\"spread break-half\">\r\n  <div class=\"spread-text\">\r\n    <p class=\"spread-kicker\">Kim loại</p>\r\n    <h3 class=\"spread-title\">Phản xạ môi trường</h3>\r\n    <p>Kim loại là vật liệu <strong>khó nhất</strong> vẽ đúng — vì nó không có \"màu riêng\" rõ ràng. Thứ bạn thấy trên mặt kim loại là <em>phản xạ của môi trường xung quanh</em>.</p>\r\n    <p>Quả cầu chrome trong phòng: phản xạ cả trần, sàn, tường, cửa sổ. Không có ánh sáng = kim loại tối thui. Có ánh sáng mạnh = highlight cực sắc, gần trắng tinh.</p>\r\n    <p>Mẹo: khi vẽ kim loại, <strong>nhìn môi trường xung quanh</strong> trước khi nhìn vật. Những gì quanh nó sẽ \"in\" lên bề mặt nó.</p>\r\n  </div>\r\n  <div class=\"spread-img\" data-img=\"IMG_02\">\r\n    <span class=\"img-sub\">🔍 IMG_02</span>\r\n    <p class=\"img-kw\">Metal chrome ball reflection environment reference</p>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"pq\">\r\n  <p class=\"pq-text\">Vật liệu không phải là <em>màu sắc</em> — vật liệu là <em>cách ánh sáng xử sự.</em></p>\r\n  <span class=\"pq-cite\">— Nguyên tắc của hội hoạ thực tế</span>\r\n</div>\r\n\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>03</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Cheat sheet</p>\r\n    <h2 class=\"div-title\">Bảng nhận diện nhanh</h2>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"el-intro\">\r\n  <div class=\"el-intro-n\">5</div>\r\n  <p class=\"el-intro-t\">Dấu hiệu nhận biết mỗi nhóm vật liệu.</p>\r\n</div>\r\n\r\n<div class=\"el-list\">\r\n  <div class=\"el-item\">\r\n    <span class=\"el-n\">M</span>\r\n    <p class=\"el-name\">Kim loại <em>Metal</em></p>\r\n    <p class=\"el-desc\">Highlight sắc + cứng. Tương phản mạnh (đen → trắng trên 1 vật). Có phản xạ môi trường.</p>\r\n  </div>\r\n  <div class=\"el-item\">\r\n    <span class=\"el-n\">G</span>\r\n    <p class=\"el-name\">Bóng nhẵn <em>Glossy</em></p>\r\n    <p class=\"el-desc\">Highlight rõ nhưng không cứng bằng kim loại. Giữ màu gốc của vật nhiều hơn.</p>\r\n  </div>\r\n  <div class=\"el-item\">\r\n    <span class=\"el-n\">D</span>\r\n    <p class=\"el-name\">Mờ đục <em>Matte</em></p>\r\n    <p class=\"el-desc\">Highlight \"dịu\". Chuyển tiếp từ sáng xuống tối rất êm. Không phản xạ gì rõ.</p>\r\n  </div>\r\n  <div class=\"el-item\">\r\n    <span class=\"el-n\">T</span>\r\n    <p class=\"el-name\">Trong suốt <em>Transparent</em></p>\r\n    <p class=\"el-desc\">Thấy được vật phía sau (có thể bị biến dạng). Có caustic (vệt sáng đặc biệt trên nền).</p>\r\n  </div>\r\n  <div class=\"el-item\">\r\n    <span class=\"el-n\">S</span>\r\n    <p class=\"el-name\">Tán xạ <em>SSS</em></p>\r\n    <p class=\"el-desc\">Rìa vật sáng nhẹ hồng/cam (ánh sáng xuyên). Core shadow không quá đậm.</p>\r\n  </div>\r\n  <div class=\"el-item el-fill-end\">\r\n    <p class=\"el-fill-text\">Đọc được<br>vật liệu<br>là đọc được<br>ánh sáng</p>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"tips\">\r\n  <div class=\"tip\"><span class=\"tip-n\">01</span><div class=\"tip-c\"><p class=\"tip-t\">Master 1 vật liệu / tháng</p><p class=\"tip-d\">Mỗi tháng tập trung 1 nhóm. Kim loại → bóng nhẵn → mờ đục → trong suốt → SSS. 5 tháng có base vững.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">02</span><div class=\"tip-c\"><p class=\"tip-t\">Reference thật, không tưởng tượng</p><p class=\"tip-d\">Đặt vật trên bàn, vẽ. Vật liệu quá phức tạp để \"nhớ\" — cần quan sát trực tiếp.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">03</span><div class=\"tip-c\"><p class=\"tip-t\">So sánh cùng 1 hình dạng</p><p class=\"tip-d\">Vẽ 5 quả cầu với 5 vật liệu khác nhau. Bạn sẽ thấy rõ đặc tính của mỗi loại.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">04</span><div class=\"tip-c\"><p class=\"tip-t\">Học từ nhiếp ảnh sản phẩm</p><p class=\"tip-d\">Ảnh product photography có ánh sáng rõ ràng, vật liệu đơn giản. Tham khảo tốt cho study.</p></div></div>\r\n</div>\r\n\r\n<div class=\"dd break-half\">\r\n  <div class=\"dd-col good\">\r\n    <div class=\"dd-head\"><span class=\"dd-badge\">+</span><span class=\"dd-title\">Nên làm</span></div>\r\n    <ul class=\"dd-list\">\r\n      <li>Nhận diện vật liệu trước khi vẽ</li>\r\n      <li>Quan sát môi trường xung quanh vật</li>\r\n      <li>Dùng reference thật cho mỗi vật liệu</li>\r\n      <li>Phân biệt highlight \"cứng\" và \"mềm\"</li>\r\n    </ul>\r\n  </div>\r\n  <div class=\"dd-col bad\">\r\n    <div class=\"dd-head\"><span class=\"dd-badge\">−</span><span class=\"dd-title\">Nên tránh</span></div>\r\n    <ul class=\"dd-list\">\r\n      <li>Vẽ mọi vật với cùng 1 cách shading</li>\r\n      <li>Vẽ kim loại mà không có phản xạ môi trường</li>\r\n      <li>Vẽ da thịt với core shadow quá đậm</li>\r\n      <li>Bỏ qua caustic và refraction của kính</li>\r\n    </ul>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"key break\">\r\n  <p class=\"key-lbl\">⭐ Điểm mấu chốt</p>\r\n  <p class=\"key-t\">Vật liệu là <em>tính cách</em> của vật trong tranh.</p>\r\n  <p class=\"key-d\">Một tượng đá cẩm thạch và một con búp bê sứ có thể có cùng hình dạng, nhưng nhờ vật liệu khác nhau — chúng cho hai cảm giác hoàn toàn khác. Học vật liệu là học ngôn ngữ để kể chuyện qua bề mặt.</p>\r\n</div>\r\n\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>04</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">FAQ</p>\r\n    <h2 class=\"div-title\">Câu hỏi thường gặp</h2>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"faq\">\r\n  <details open>\r\n    <summary>Khó nhất là vật liệu nào?<span class=\"faq-icon\">−</span></summary>\r\n    <p>Kim loại và trong suốt. Kim loại khó vì không có \"màu riêng\" — hoàn toàn phụ thuộc môi trường. Trong suốt khó vì có khúc xạ, phản xạ và nội dung phía sau chồng lên nhau. Cả hai đòi hỏi hiểu quang học.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Chì có vẽ được kim loại không?<span class=\"faq-icon\">+</span></summary>\r\n    <p>Có — và rất tốt. Chì có dải sắc độ rộng (đen → trắng giấy) — phù hợp với tương phản mạnh của kim loại. Nhiều họa sĩ chuyên vẽ kim loại bằng chì/than thay vì màu.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Da người thuộc loại nào?<span class=\"faq-icon\">+</span></summary>\r\n    <p>Subsurface Scattering (SSS). Ánh sáng xuyên nhẹ vào da, phản xạ phần nào qua máu rồi ra lại — tạo hồng ở rìa, đặc biệt ở tai, mũi, ngón tay. Bỏ qua SSS → da trông nhựa, không sống.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Sách hoặc khoá nào học vật liệu tốt?<span class=\"faq-icon\">+</span></summary>\r\n    <p>James Gurney \"Color and Light\" có chương xuất sắc về vật liệu. Proko có series YouTube miễn phí về material. Ở cấp độ cao: CGMA (CG Master Academy) có khoá \"Material Study\" chuyên sâu cho 3D và concept art.</p>\r\n  </details>\r\n</div>\r\n";

